SELECT COUNT(*) AS pending_adjustments
FROM size_adjustment_history
WHERE status = 'Proposed';

SELECT customer_id, date_recommended
FROM size_recommendations
ORDER BY customer_id, date_recommended;

SELECT customer_id, MAX(date_taken) AS latest_measurement_date
FROM customer_measurements
WHERE customer_id = 1;

SELECT MAX(date_taken)
FROM customer_measurements
WHERE customer_id = 1;
